const config = {
  "previewFeatures": [],
  "clientVersion": "7.5.0",
  "engineVersion": "280c870be64f457428992c43c1f6d557fab6e29e",
  "activeProvider": "postgresql",
  "inlineSchema": "// =============================================================================\n// Learnova eLearning Platform — Prisma Schema\n// Database: PostgreSQL\n// ORM: Prisma\n// =============================================================================\n\ngenerator client {\n  provider   = \"prisma-client-js\"\n  output     = \"../generated/prisma\"\n  engineType = \"library\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// =============================================================================\n// ENUMS\n// =============================================================================\n\nenum Role {\n  ADMIN\n  INSTRUCTOR\n  LEARNER\n}\n\nenum LessonType {\n  VIDEO\n  DOCUMENT\n  IMAGE\n  QUIZ\n}\n\nenum CourseVisibility {\n  EVERYONE\n  SIGNED_IN\n}\n\nenum CourseAccess {\n  OPEN\n  ON_INVITATION\n  ON_PAYMENT\n}\n\nenum EnrollmentStatus {\n  YET_TO_START\n  IN_PROGRESS\n  COMPLETED\n}\n\nenum AttachmentType {\n  FILE\n  LINK\n}\n\nenum QuizAttemptStatus {\n  IN_PROGRESS\n  COMPLETED\n}\n\nenum PaymentStatus {\n  PENDING\n  SUCCESS\n  FAILED\n  REFUNDED\n}\n\nenum PaymentProvider {\n  RAZORPAY\n  PAYPAL\n}\n\nenum BadgeLevel {\n  NEWBIE // 20 pts\n  EXPLORER // 40 pts\n  ACHIEVER // 60 pts\n  SPECIALIST // 80 pts\n  EXPERT // 100 pts\n  MASTER // 120 pts\n}\n\n// =============================================================================\n// USER\n// =============================================================================\n\nmodel User {\n  id           String      @id @default(cuid())\n  email        String      @unique\n  passwordHash String\n  firstName    String\n  lastName     String\n  avatarUrl    String?\n  role         Role        @default(LEARNER)\n  totalPoints  Int         @default(0)\n  badgeLevel   BadgeLevel?\n  isActive     Boolean     @default(true)\n  createdAt    DateTime    @default(now())\n  updatedAt    DateTime    @updatedAt\n\n  // Relations\n  managedCourses      Course[]           @relation(\"CourseAdmin\")\n  createdCourses      Course[]           @relation(\"CourseCreator\")\n  enrollments         Enrollment[]\n  quizAttempts        QuizAttempt[]\n  lessonProgress      LessonProgress[]\n  reviews             Review[]\n  sentInvitations     Invitation[]       @relation(\"InvitedBy\")\n  receivedInvitations Invitation[]       @relation(\"InvitedUser\")\n  pointTransactions   PointTransaction[]\n  payments            Payment[]\n  refreshTokens       RefreshToken[]\n\n  @@index([email])\n  @@index([role])\n  @@map(\"users\")\n}\n\n// =============================================================================\n// REFRESH TOKEN\n// =============================================================================\n\nmodel RefreshToken {\n  id        String   @id @default(cuid())\n  token     String   @unique\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n  @@map(\"refresh_tokens\")\n}\n\n// =============================================================================\n// COURSE\n// =============================================================================\n\nmodel Course {\n  id            String    @id @default(cuid())\n  title         String\n  slug          String    @unique\n  description   String? // rich text — Description tab\n  shortDesc     String? // shown on course cards\n  coverImageUrl String?\n  isPublished   Boolean   @default(false)\n  publishedAt   DateTime?\n  websiteUrl    String? // required when isPublished = true\n  viewsCount    Int       @default(0)\n  totalDuration Int       @default(0) // computed, in seconds\n\n  visibility CourseVisibility @default(EVERYONE)\n  accessRule CourseAccess     @default(OPEN)\n  price      Decimal?         @db.Decimal(10, 2) // required when ON_PAYMENT\n\n  createdById String\n  createdBy   User   @relation(\"CourseCreator\", fields: [createdById], references: [id])\n\n  adminId String?\n  admin   User?   @relation(\"CourseAdmin\", fields: [adminId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  tags        CourseTag[]\n  lessons     Lesson[]\n  quizzes     Quiz[]\n  enrollments Enrollment[]\n  reviews     Review[]\n  invitations Invitation[]\n  payments    Payment[]\n\n  @@index([isPublished])\n  @@index([visibility])\n  @@index([createdById])\n  @@index([adminId])\n  @@map(\"courses\")\n}\n\n// =============================================================================\n// TAG  (many-to-many via CourseTag)\n// =============================================================================\n\nmodel Tag {\n  id      String      @id @default(cuid())\n  name    String      @unique\n  courses CourseTag[]\n\n  @@map(\"tags\")\n}\n\nmodel CourseTag {\n  courseId String\n  tagId    String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  tag      Tag    @relation(fields: [tagId], references: [id], onDelete: Cascade)\n\n  @@id([courseId, tagId])\n  @@map(\"course_tags\")\n}\n\n// =============================================================================\n// LESSON\n// =============================================================================\n\nmodel Lesson {\n  id       String @id @default(cuid())\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  title       String\n  type        LessonType\n  description String? // rich text shown above viewer\n  order       Int        @default(0)\n\n  // VIDEO fields\n  videoUrl String? // YouTube / Google Drive embed URL\n  duration Int? // in seconds\n\n  // DOCUMENT / IMAGE fields\n  fileUrl       String? // Cloudinary CDN URL\n  fileKey       String? // Cloudinary public_id for deletion\n  allowDownload Boolean @default(false)\n\n  responsibleName String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  attachments LessonAttachment[]\n  progress    LessonProgress[]\n  quizLesson  QuizLesson?\n\n  @@index([courseId, order])\n  @@map(\"lessons\")\n}\n\n// =============================================================================\n// LESSON ATTACHMENT\n// =============================================================================\n\nmodel LessonAttachment {\n  id       String @id @default(cuid())\n  lessonId String\n  lesson   Lesson @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n\n  type    AttachmentType\n  label   String?\n  fileUrl String?\n  fileKey String?\n  linkUrl String?\n\n  createdAt DateTime @default(now())\n\n  @@index([lessonId])\n  @@map(\"lesson_attachments\")\n}\n\n// =============================================================================\n// QUIZ\n// =============================================================================\n\nmodel Quiz {\n  id       String @id @default(cuid())\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  title       String\n  description String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  questions  Question[]\n  rewards    QuizReward[]\n  attempts   QuizAttempt[]\n  quizLesson QuizLesson?\n\n  @@index([courseId])\n  @@map(\"quizzes\")\n}\n\n// =============================================================================\n// QUIZ <-> LESSON bridge  (1:1)\n// Links a Lesson of type=QUIZ to its Quiz record\n// =============================================================================\n\nmodel QuizLesson {\n  lessonId String @unique\n  quizId   String @unique\n  lesson   Lesson @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n  quiz     Quiz   @relation(fields: [quizId], references: [id], onDelete: Cascade)\n\n  @@map(\"quiz_lessons\")\n}\n\n// =============================================================================\n// QUIZ REWARD  (points per attempt tier)\n// =============================================================================\n\nmodel QuizReward {\n  id     String @id @default(cuid())\n  quizId String\n  quiz   Quiz   @relation(fields: [quizId], references: [id], onDelete: Cascade)\n\n  attemptNumber Int // 1 = first try, 2 = second, 3 = third, 4 = fourth and beyond\n  points        Int\n\n  @@unique([quizId, attemptNumber])\n  @@map(\"quiz_rewards\")\n}\n\n// =============================================================================\n// QUESTION\n// =============================================================================\n\nmodel Question {\n  id     String @id @default(cuid())\n  quizId String\n  quiz   Quiz   @relation(fields: [quizId], references: [id], onDelete: Cascade)\n\n  text  String\n  order Int    @default(0)\n\n  // Relations\n  options QuestionOption[]\n  answers AttemptAnswer[]\n\n  @@index([quizId, order])\n  @@map(\"questions\")\n}\n\n// =============================================================================\n// QUESTION OPTION\n// =============================================================================\n\nmodel QuestionOption {\n  id         String   @id @default(cuid())\n  questionId String\n  question   Question @relation(fields: [questionId], references: [id], onDelete: Cascade)\n\n  text      String\n  isCorrect Boolean @default(false)\n  order     Int     @default(0)\n\n  // Relations\n  answers AttemptAnswer[]\n\n  @@index([questionId])\n  @@map(\"question_options\")\n}\n\n// =============================================================================\n// ENROLLMENT  (Learner <-> Course with full progress state)\n// =============================================================================\n\nmodel Enrollment {\n  id       String @id @default(cuid())\n  userId   String\n  user     User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  status            EnrollmentStatus @default(YET_TO_START)\n  completionPercent Float            @default(0) // 0.0 – 100.0\n  timeSpentSeconds  Int              @default(0)\n\n  enrolledAt  DateTime  @default(now())\n  startedAt   DateTime?\n  completedAt DateTime?\n  updatedAt   DateTime  @updatedAt\n\n  // Relations\n  lessonProgress LessonProgress[]\n  payment        Payment?\n\n  @@unique([userId, courseId])\n  @@index([userId])\n  @@index([courseId])\n  @@index([status])\n  @@map(\"enrollments\")\n}\n\n// =============================================================================\n// LESSON PROGRESS  (per learner per lesson)\n// =============================================================================\n\nmodel LessonProgress {\n  id           String     @id @default(cuid())\n  enrollmentId String\n  enrollment   Enrollment @relation(fields: [enrollmentId], references: [id], onDelete: Cascade)\n  lessonId     String\n  lesson       Lesson     @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n  userId       String\n  user         User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  isCompleted      Boolean @default(false)\n  isInProgress     Boolean @default(false)\n  timeSpentSeconds Int     @default(0)\n\n  startedAt   DateTime?\n  completedAt DateTime?\n\n  @@unique([enrollmentId, lessonId])\n  @@index([userId, lessonId])\n  @@map(\"lesson_progress\")\n}\n\n// =============================================================================\n// QUIZ ATTEMPT\n// =============================================================================\n\nmodel QuizAttempt {\n  id     String @id @default(cuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  quizId String\n  quiz   Quiz   @relation(fields: [quizId], references: [id], onDelete: Cascade)\n\n  attemptNumber Int\n  status        QuizAttemptStatus @default(IN_PROGRESS)\n  pointsEarned  Int               @default(0)\n  score         Float? // percentage of correct answers\n\n  startedAt   DateTime  @default(now())\n  completedAt DateTime?\n\n  // Relations\n  answers AttemptAnswer[]\n\n  @@index([userId, quizId])\n  @@map(\"quiz_attempts\")\n}\n\n// =============================================================================\n// ATTEMPT ANSWER  (one row per question per attempt)\n// =============================================================================\n\nmodel AttemptAnswer {\n  id        String      @id @default(cuid())\n  attemptId String\n  attempt   QuizAttempt @relation(fields: [attemptId], references: [id], onDelete: Cascade)\n\n  questionId String\n  question   Question @relation(fields: [questionId], references: [id])\n\n  selectedOptionId String\n  selectedOption   QuestionOption @relation(fields: [selectedOptionId], references: [id])\n\n  isCorrect Boolean\n\n  @@unique([attemptId, questionId])\n  @@index([attemptId])\n  @@map(\"attempt_answers\")\n}\n\n// =============================================================================\n// POINT TRANSACTION  (immutable audit log for every point award)\n// =============================================================================\n\nmodel PointTransaction {\n  id     String @id @default(cuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  points        Int // positive = earned\n  reason        String // e.g. \"Quiz 'Basics Quiz' — attempt 1\"\n  quizAttemptId String? // FK to the attempt that triggered the award\n\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n  @@map(\"point_transactions\")\n}\n\n// =============================================================================\n// PAYMENT\n// =============================================================================\n\nmodel Payment {\n  id           String      @id @default(cuid())\n  userId       String\n  user         User        @relation(fields: [userId], references: [id], onDelete: Cascade)\n  courseId     String\n  course       Course      @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  enrollmentId String?     @unique\n  enrollment   Enrollment? @relation(fields: [enrollmentId], references: [id])\n\n  provider PaymentProvider\n  status   PaymentStatus   @default(PENDING)\n  amount   Decimal         @db.Decimal(10, 2)\n  currency String          @default(\"INR\")\n\n  // Provider-specific fields\n  providerOrderId   String? // Razorpay order_id / PayPal order id — set before redirect\n  providerPaymentId String? // Razorpay payment_id / PayPal capture id — set after success\n  providerSignature String? // Razorpay webhook signature for verification\n\n  failureReason String? // populated if status = FAILED\n  refundedAt    DateTime? // populated if status = REFUNDED\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([courseId])\n  @@index([status])\n  @@map(\"payments\")\n}\n\n// =============================================================================\n// REVIEW\n// =============================================================================\n\nmodel Review {\n  id       String @id @default(cuid())\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  userId   String\n  user     User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  rating  Int // 1 – 5\n  comment String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([courseId, userId])\n  @@index([courseId])\n  @@map(\"reviews\")\n}\n\n// =============================================================================\n// INVITATION  (Add Attendees wizard + On Invitation access rule)\n// =============================================================================\n\nmodel Invitation {\n  id       String @id @default(cuid())\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  email       String\n  invitedById String\n  invitedBy   User   @relation(\"InvitedBy\", fields: [invitedById], references: [id])\n\n  invitedUserId String?\n  invitedUser   User?   @relation(\"InvitedUser\", fields: [invitedUserId], references: [id])\n\n  token      String    @unique @default(cuid())\n  acceptedAt DateTime?\n  expiresAt  DateTime?\n  createdAt  DateTime  @default(now())\n\n  @@unique([courseId, email])\n  @@index([courseId])\n  @@index([email])\n  @@map(\"invitations\")\n}\n"
}

